import React, { useState, useEffect, useRef, useCallback } from 'react';
import Lenis from '@studio-freight/lenis';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { TextPlugin } from 'gsap/TextPlugin';
import { motion, AnimatePresence } from 'framer-motion';
import Loader from './components/Loader';
import CustomCursor from './components/CustomCursor';
import Navigation from './components/Navigation';
import HeroSection from './components/HeroSection';
import FloatingBalloons from './components/FloatingBalloons';
import TimelineSection from './components/TimelineSection';
import PhotoCarousel from './components/PhotoCarousel';
import MessageSection from './components/MessageSection';
import CakeSection from './components/CakeSection';
import WishesSection from './components/WishesSection';
import MicroInteractions from './components/MicroInteractions';
import FinalSurprise from './components/FinalSurprise';
import RosesSection from './components/RosesSection';
import CorkboardSection from './components/CorkboardSection';
import GiftBoxSection from './components/GiftBoxSection';
import EmojiParade from './components/EmojiParade';
import useShake from './hooks/useShake';

gsap.registerPlugin(ScrollTrigger, TextPlugin);

export default function App() {
  const [loaded, setLoaded] = useState(false);
  const lenisRef = useRef(null);

  // --- Shake to Hug Logic ---
  const [hugsSent, setHugsSent] = useState(0);
  const [showToast, setShowToast] = useState(false);
  const [floatingHugs, setFloatingHugs] = useState([]);

  const handleShake = useCallback(() => {
    setHugsSent(prev => prev + 1);
    setShowToast(true);

    // Spawn 5-10 random floating hearts
    const newHugs = Array.from({ length: Math.floor(Math.random() * 5) + 5 }, (_, i) => ({
      id: Date.now() + i,
      left: Math.random() * 100, // random start X position %
      size: Math.random() * 2 + 1, // random scale
    }));

    setFloatingHugs(prev => [...prev, ...newHugs]);

    // Cleanup toast after 3 seconds
    setTimeout(() => setShowToast(false), 3000);

    // Cleanup floating elements after animation ends
    setTimeout(() => {
      setFloatingHugs(prev => prev.filter(hug => !newHugs.find(n => n.id === hug.id)));
    }, 4000);
  }, []);

  const { isSupported, permissionGranted, requestPermission } = useShake(handleShake, { threshold: 20 });
  // --------------------------

  // Initialize Lenis smooth scroll
  useEffect(() => {
    // Console Easter Egg (Secret Love Note)
    console.log(
      '%cEven the code behind this website thinks you\'re beautiful. Happy 20th, Shariya! ≡ƒñì',
      'font-size: 18px; font-style: italic; font-family: "Georgia", serif; color: #ff6eb4; background: #0a0010; padding: 20px; border: 2px solid #ffd700; border-radius: 10px; text-shadow: 0 0 10px rgba(255, 110, 180, 0.5);'
    );

    const lenis = new Lenis({
      lerp: 0.08,
      duration: 1.4,
      smoothWheel: true,
      smoothTouch: false,
    });

    lenisRef.current = lenis;

    // Connect Lenis to GSAP ScrollTrigger
    lenis.on('scroll', ScrollTrigger.update);

    gsap.ticker.add((time) => {
      lenis.raf(time * 1000);
    });

    gsap.ticker.lagSmoothing(0);

    return () => {
      lenis.destroy();
    };
  }, []);

  // Prevent scroll during loading
  useEffect(() => {
    if (!loaded) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
  }, [loaded]);

  return (
    <>
      <CustomCursor />
      <MicroInteractions />
      <Navigation />

      {/* Shake to Hug Toast Notification */}
      <AnimatePresence>
        {showToast && (
          <motion.div
            initial={{ opacity: 0, y: -50, x: '-50%' }}
            animate={{ opacity: 1, y: 20, x: '-50%' }}
            exit={{ opacity: 0, y: -50, x: '-50%' }}
            style={{
              position: 'fixed', top: 0, left: '50%', zIndex: 999999,
              background: 'rgba(255, 110, 180, 0.9)', color: '#fff',
              padding: '1rem 2rem', borderRadius: '50px',
              fontFamily: 'var(--font-sans)', fontWeight: 600,
              boxShadow: '0 10px 30px rgba(255, 110, 180, 0.4)',
              backdropFilter: 'blur(10px)', border: '1px solid rgba(255,255,255,0.3)',
              display: 'flex', alignItems: 'center', gap: '10px'
            }}
          >
            <span>≡ƒñù</span> Hug sent to Shariya! (Total: {hugsSent})
          </motion.div>
        )}
      </AnimatePresence>

      {/* Floating Hearts spawned by Shaking */}
      <div style={{ position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 999998, overflow: 'hidden' }}>
        <AnimatePresence>
          {floatingHugs.map(hug => (
            <motion.div
              key={hug.id}
              initial={{ opacity: 1, y: '100vh', x: `${hug.left}vw`, scale: hug.size }}
              animate={{ opacity: 0, y: '-20vh', x: `${hug.left + (Math.random() * 20 - 10)}vw` }}
              exit={{ opacity: 0 }}
              transition={{ duration: 3 + Math.random(), ease: 'easeOut' }}
              style={{ position: 'absolute', fontSize: '3rem', filter: 'drop-shadow(0 0 10px rgba(255,110,180,0.5))' }}
            >
              ≡ƒñì
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      {/* iOS 13+ Permission Prompt for Accelerometer */}
      {isSupported && !permissionGranted && (
        <div style={{
          position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)',
          zIndex: 999999, background: 'rgba(10,0,20,0.9)', padding: '15px 25px',
          borderRadius: '12px', border: '1px solid var(--starlight-gold)',
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px',
          fontFamily: 'var(--font-sans)', color: '#fff', textAlign: 'center', fontSize: '0.9rem'
        }}>
          <p>Shake your phone to send a hug! ≡ƒñù</p>
          <button 
            onClick={requestPermission}
            style={{ 
              background: 'var(--starlight-gold)', color: '#000', border: 'none',
              padding: '8px 20px', borderRadius: '20px', fontWeight: 'bold', cursor: 'pointer'
            }}
          >
            Enable Motion
          </button>
        </div>
      )}

      <Loader onComplete={() => setLoaded(true)} />

      <main style={{ opacity: loaded ? 1 : 0, transition: 'opacity 0.5s ease' }}>
        {/* Hero + Balloons */}
        <div style={{ position: 'relative' }}>
          <HeroSection />
          <FloatingBalloons />
        </div>

        {/* Storytelling Timeline */}
        <TimelineSection />

        {/* 3D Growing Roses */}
        <RosesSection />

        {/* 3D Memories Corkboard */}
        <CorkboardSection />

        {/* Photo Carousel */}
        <PhotoCarousel />

        {/* 3D Interactive Gift Box */}
        <GiftBoxSection />

        {/* Birthday Message */}
        <MessageSection />

        {/* Interactive Cake */}
        <CakeSection />

        {/* Final Wishes + Fireworks */}
        <WishesSection />

        {/* The Final 'Open if you love me' Letter */}
        <FinalSurprise />

        {/* Dancing Emoji Parade */}
        <EmojiParade />

        {/* Footer */}
        <footer style={{
          padding: '3rem 2rem',
          textAlign: 'center',
          fontFamily: 'var(--font-serif)',
          color: 'var(--lavender-glow)',
          fontSize: '0.875rem',
          letterSpacing: '0.2em',
          opacity: 0.5,
          background: 'var(--deep-void)',
        }}>
          <p>Made with ≡ƒÆû for Shariya</p>
          <p style={{ marginTop: '0.5rem', fontSize: '0.75rem' }}>
            Γ£ª March 11th ┬╖ Twenty Γ£ª
          </p>
          <p style={{ marginTop: '0.5rem', fontSize: '0.65rem', opacity: 0.6 }}>
            {isSupported ? "Shake your phone to send her a hug!" : ""}
          </p>
        </footer>
      </main>
    </>
  );
}

import React, { useRef, useState, useMemo, memo, useCallback } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import * as THREE from 'three';
import { useReveal } from '../hooks/useReveal';
import { motion, AnimatePresence } from 'framer-motion';

// Simple flame glow
const Flame = memo(function Flame({ position, isLit }) {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (ref.current && isLit) {
      const t = clock.getElapsedTime();
      ref.current.scale.setScalar(0.8 + Math.sin(t * 8) * 0.2);
      ref.current.material.opacity = 0.7 + Math.sin(t * 6) * 0.3;
    } else if (ref.current && !isLit) {
      ref.current.material.opacity = Math.max(0, ref.current.material.opacity - 0.03);
    }
  });
  return (
    <mesh ref={ref} position={position}>
      <sphereGeometry args={[0.06, 6, 6]} />
      <meshBasicMaterial color="#ffaa33" transparent opacity={isLit ? 0.9 : 0} />
    </mesh>
  );
});

const Candle = memo(function Candle({ position, isLit }) {
  return (
    <group position={position}>
      <mesh>
        <cylinderGeometry args={[0.03, 0.03, 0.45, 6]} />
        <meshBasicMaterial color="#fff5e6" />
      </mesh>
      <Flame position={[0, 0.3, 0]} isLit={isLit} />
    </group>
  );
});

const FrostingDots = memo(function FrostingDots({ radius, y, count = 10, color = '#ff6eb4' }) {
  const dots = useMemo(() =>
    Array.from({ length: count }, (_, i) => {
      const angle = (i / count) * Math.PI * 2;
      return [Math.cos(angle) * radius, y, Math.sin(angle) * radius];
    }),
  [radius, y, count]);

  return (
    <group>
      {dots.map((pos, i) => (
        <mesh key={i} position={pos}>
          <sphereGeometry args={[0.035, 4, 4]} />
          <meshBasicMaterial color={color} />
        </mesh>
      ))}
    </group>
  );
});

const BirthdayCake = memo(function BirthdayCake({ onBlow, onEat }) {
  const [candlesLit, setCandlesLit] = useState(true);
  const groupRef = useRef();

  const handleClick = () => {
    if (candlesLit) {
      setCandlesLit(false);
      setTimeout(() => { if (onBlow) onBlow(); }, 1000);
    } else {
      // Cake bounce animation
      if (groupRef.current) {
        let t = 0;
        const bounce = setInterval(() => {
          t += 0.1;
          const scale = 1 - Math.sin(t * Math.PI) * 0.1;
          const y = Math.sin(t * Math.PI) * 0.1;
          groupRef.current.scale.set(1, scale, 1);
          groupRef.current.position.y = y;
          if (t >= 1) {
            clearInterval(bounce);
            groupRef.current.scale.set(1, 1, 1);
            groupRef.current.position.y = 0;
          }
        }, 16);
      }
      if (onEat) onEat();
    }
  };

  const candlePositions = [[0, 1.55, 0], [0.25, 1.55, 0.1], [-0.25, 1.55, -0.1], [0.1, 1.55, -0.2], [-0.1, 1.55, 0.2]];

  return (
    <group ref={groupRef} onClick={handleClick}>
      {/* Layer 1 */}
      <mesh position={[0, 0, 0]}>
        <cylinderGeometry args={[1.1, 1.1, 0.55, 20]} />
        <meshStandardMaterial color="#f5e6cc" roughness={0.8} />
      </mesh>
      <FrostingDots radius={1.12} y={0.28} count={12} color="#ff6eb4" />

      {/* Layer 2 */}
      <mesh position={[0, 0.5, 0]}>
        <cylinderGeometry args={[0.8, 0.8, 0.45, 20]} />
        <meshStandardMaterial color="#ffe4e8" roughness={0.7} />
      </mesh>
      <FrostingDots radius={0.82} y={0.73} count={10} color="#ffd700" />

      {/* Layer 3 */}
      <mesh position={[0, 0.95, 0]}>
        <cylinderGeometry args={[0.55, 0.55, 0.45, 20]} />
        <meshStandardMaterial color="#fff0f5" roughness={0.6} />
      </mesh>
      <FrostingDots radius={0.57} y={1.17} count={8} color="#e8c4ff" />

      {candlePositions.map((pos, i) => (
        <Candle key={i} position={pos} isLit={candlesLit} />
      ))}

      {candlesLit && <pointLight position={[0, 1.8, 0]} intensity={0.5} color="#ffa500" distance={3} />}
    </group>
  );
});

export default memo(function CakeSection() {
  const sectionRef = useReveal({ y: 40 });
  const [blownOut, setBlownOut] = useState(false);
  const [slices, setSlices] = useState([]);
  const [sliceCount, setSliceCount] = useState(0);

  const handleEat = useCallback(() => {
    setSliceCount(c => c + 1);
    const newSlice = {
      id: Date.now(),
      x: 30 + Math.random() * 40, // percentage 30-70%
      y: 30 + Math.random() * 30,
      rot: (Math.random() - 0.5) * 30
    };
    setSlices(prev => [...prev.slice(-4), newSlice]);
  }, []);

  return (
    <section id="cake" ref={sectionRef} className="section cake-section" style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
      position: 'relative'
    }}>
      <h2 style={{
        fontFamily: 'var(--font-serif)', fontSize: 'clamp(2rem, 4vw, 3rem)',
        fontWeight: 300, color: 'var(--rose-pink)', marginBottom: '1rem',
        letterSpacing: '0.1em', textAlign: 'center', zIndex: 2,
      }}>
        Make a Wish Γ£ª
      </h2>
      <div className="cake-canvas interactive" style={{ maxWidth: '800px', margin: '0 auto', position: 'relative' }}>
        <Canvas
          camera={{ position: [3, 3, 3], fov: 40 }}
          gl={{ antialias: false, powerPreference: 'high-performance' }}
          dpr={[1, 1.5]}
        >
          <ambientLight intensity={0.5} />
          <directionalLight position={[5, 8, 3]} intensity={0.5} />
          <BirthdayCake onBlow={() => setBlownOut(true)} onEat={handleEat} />
          <OrbitControls enableZoom={false} enablePan={false}
            minPolarAngle={Math.PI / 6} maxPolarAngle={Math.PI / 2.2}
            autoRotate autoRotateSpeed={0.5} />
        </Canvas>

        {/* Floating slice easter eggs */}
        <AnimatePresence>
          {slices.map(s => (
            <motion.div key={s.id}
              style={{
                position: 'absolute', left: `${s.x}%`, top: `${s.y}%`,
                fontFamily: 'var(--font-serif)', fontSize: '2rem',
                color: 'var(--starlight-gold)', fontWeight: 'bold',
                pointerEvents: 'none', zIndex: 10,
                textShadow: '0 0 10px rgba(255,215,0,0.5)'
              }}
              initial={{ opacity: 1, y: 0, scale: 0.5, rotate: s.rot }}
              animate={{ opacity: 0, y: -100, scale: 1.2, rotate: s.rot + 10 }}
              transition={{ duration: 1.5, ease: 'easeOut' }}
              onAnimationComplete={() => setSlices(prev => prev.filter(x => x.id !== s.id))}
            >
              +1 Slice ≡ƒì░
            </motion.div>
          ))}
        </AnimatePresence>
      </div>

      <p className="blow-text" style={{ transition: 'opacity 0.5s' }}>
        {!blownOut && 'Γ£¿ Click the cake to blow out the candles Γ£¿'}
        {blownOut && sliceCount === 0 && '≡ƒÄë Wish granted! Click the cake to grab a slice!'}
        {blownOut && sliceCount > 0 && `You've eaten ${sliceCount} slice${sliceCount > 1 ? 's' : ''} ≡ƒì░`}
      </p>
    </section>
  );
});

import React, { useState, useRef, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// Sample memories for the corkboard
const MEMORIES = [
  { id: 1, src: '/photos/photo1.jpg', caption: 'Memories ≡ƒîƒ', rotation: -5, x: 10, y: 15 },
  { id: 2, src: '/photos/photo2.jpg', caption: 'Always Smiling Γ£¿', rotation: 8, x: 40, y: 5 },
  { id: 3, src: '/photos/photo3.jpg', caption: 'Special Moments ≡ƒñì', rotation: -12, x: 75, y: 12 },
  { id: 4, src: '/photos/photo4.jpg', caption: 'Adventures ≡ƒîè', rotation: 15, x: 20, y: 50 },
  { id: 5, src: '/photos/photo5.jpg', caption: 'Favorite Day ≡ƒî╕', rotation: -8, x: 55, y: 45 },
  { id: 6, src: '/photos/photo6.jpg', caption: 'Just Us ≡ƒÆ½', rotation: 10, x: 80, y: 60 }
];

const Polaroid = memo(({ src, caption, rotation, x, y, onClick, delay = 0 }) => {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0, rotate: rotation - 20, z: -100 }}
      whileInView={{ opacity: 1, scale: 1, rotate: rotation, z: 0 }}
      viewport={{ once: true, margin: '-100px' }}
      transition={{ duration: 0.8, delay, type: 'spring', bounce: 0.4 }}
      className="cork-polaroid interactive"
      style={{ left: `${x}%`, top: `${y}%` }}
      onClick={onClick}
      whileHover={{ 
        scale: 1.15, 
        rotate: 0, 
        z: 50, // Lifts the polaroid off the corkboard in 3D space
        boxShadow: '0 25px 40px rgba(0,0,0,0.6)'
      }}
    >
      {/* The Push Pin */}
      <div className="push-pin" />
      
      <div className="cork-polaroid-img">
        <img src={src} alt={caption} loading="lazy" />
      </div>
      <div className="cork-polaroid-caption">
        {caption}
      </div>
    </motion.div>
  );
});

export default function CorkboardSection() {
  const [selectedImage, setSelectedImage] = useState(null);

  return (
    <section className="section" style={{ position: 'relative', overflow: 'hidden' }}>
      
      {/* 3D Corkboard Container */}
      <div className="corkboard-container">
        
        {/* Draw strings connecting the photos (SVG) */}
        <svg className="cork-strings" viewBox="0 0 100 100" preserveAspectRatio="none">
          <path d="M 15 25 Q 25 10 45 15" stroke="rgba(255,255,255,0.3)" strokeWidth="0.2" fill="none" />
          <path d="M 45 15 Q 60 25 80 22" stroke="rgba(255,255,255,0.3)" strokeWidth="0.2" fill="none" />
          <path d="M 25 60 Q 40 45 60 55" stroke="rgba(255,255,255,0.3)" strokeWidth="0.2" fill="none" />
          <path d="M 60 55 Q 70 70 85 70" stroke="rgba(255,255,255,0.3)" strokeWidth="0.2" fill="none" />
          <path d="M 15 25 Q 20 45 25 60" stroke="rgba(255,255,255,0.3)" strokeWidth="0.2" fill="none" strokeDasharray="1,1"/>
        </svg>

        {MEMORIES.map((mem, i) => (
          <Polaroid 
            key={mem.id} 
            {...mem} 
            delay={i * 0.15}
            onClick={() => setSelectedImage(mem)}
          />
        ))}
      </div>

      {/* Lightbox Overlay */}
      <AnimatePresence>
        {selectedImage && (
          <motion.div 
            className="lightbox-overlay"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setSelectedImage(null)}
          >
            <motion.div 
              className="lightbox-polaroid"
              initial={{ scale: 0.8, y: 50 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.8, y: 50 }}
              onClick={e => e.stopPropagation()}
            >
              <button 
                className="lightbox-close interactive"
                onClick={() => setSelectedImage(null)}
              >
                Γ£ò
              </button>
              <div className="lightbox-img-wrapper">
                <img src={selectedImage.src} alt={selectedImage.caption} />
              </div>
              <div className="lightbox-caption">
                {selectedImage.caption}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
}

import React, { useEffect, useRef, memo } from 'react';
import { motion } from 'framer-motion';

const EMOJIS = ['≡ƒÄé', '≡ƒî╣', '≡ƒÄê', 'Γ¡É', '≡ƒÆ½', '≡ƒªï', '≡ƒî╕', '≡ƒÄë', 'Γ£¿', '≡ƒÆ¥'];

const GlitterTrail = memo(() => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let animationFrameId;
    let particles = [];

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = 100; // Expected height of the parade container
    };

    window.addEventListener('resize', resize);
    resize();

    // Spawns particles periodically to simulate a glitter trail behind the emojis
    const spawnParticles = () => {
      // Create a few random particles across the width to simulate the marquee trail
      for (let i = 0; i < 3; i++) {
        particles.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          radius: Math.random() * 2 + 1,
          color: Math.random() > 0.5 ? '#ffd700' : '#ff6eb4',
          alpha: 1,
          vy: Math.random() * -1 - 0.5, // Float up slightly
        });
      }
    };

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      
      if (Math.random() < 0.3) spawnParticles();

      particles.forEach((p, i) => {
        p.alpha -= 0.02;
        p.y += p.vy;

        if (p.alpha <= 0) {
          particles.splice(i, 1);
        } else {
          ctx.save();
          ctx.globalAlpha = p.alpha;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
          ctx.fillStyle = p.color;
          ctx.fill();
          
          // Add a little glow
          ctx.shadowBlur = 5;
          ctx.shadowColor = p.color;
          ctx.restore();
        }
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', pointerEvents: 'none', zIndex: 1 }} 
    />
  );
});

export default function EmojiParade() {
  // We duplicate the array to create a seamless infinite marquee
  const paradeItems = [...EMOJIS, ...EMOJIS, ...EMOJIS];

  return (
    <div className="emoji-parade-container">
      <GlitterTrail />
      <div className="emoji-marquee">
        {paradeItems.map((emoji, index) => (
